// ── ICON ───────────────────────────────────────────────────────────────
function makeIcon(color, active) {
    const shadow = color + '88';
    return L.divIcon({
        className: '',
        html: `<div class="custom-marker${active ? ' active' : ''}" style="background:${color};box-shadow:0 4px 14px ${shadow}"></div>`,
        iconSize: [36, 36],
        iconAnchor: [18, 36],
    });
}

// ── PANEL REFS ─────────────────────────────────────────────────────────
const panel            = document.getElementById('side-panel');
const closeBtn         = document.getElementById('close-btn');
const panelImg         = document.getElementById('panel-img');
const panelPlaceholder = document.getElementById('panel-img-placeholder');
const panelTag         = document.getElementById('panel-tag');
const panelName        = document.getElementById('panel-name');
const panelLat         = document.getElementById('panel-lat');
const panelLng         = document.getElementById('panel-lng');
const panelDetails     = document.getElementById('panel-details');
const panelPills       = document.getElementById('panel-pills');
const hint             = document.getElementById('hint');

// ── STATE ──────────────────────────────────────────────────────────────
let activeMarker = null;
let activeLocIdx = null;

// ── OPEN PANEL ─────────────────────────────────────────────────────────
function openPanel(loc, marker) {
    // Deactivate previous
    if (activeMarker && activeLocIdx !== null) {
        activeMarker.setIcon(makeIcon(LOCATIONS[activeLocIdx].color, false));
    }
    activeMarker = marker;
    activeLocIdx = LOCATIONS.indexOf(loc);
    marker.setIcon(makeIcon(loc.color, true));

    panelTag.textContent     = loc.tag || 'Location';
    panelName.textContent    = loc.name;
    panelLat.textContent     = loc.lat.toFixed(6);
    panelLng.textContent     = loc.lng.toFixed(6);
    panelDetails.textContent = loc.details || '';

    panelPills.innerHTML = '';
    (loc.pills || []).forEach(p => {
        const pill = document.createElement('div');
        pill.className = 'info-pill';
        pill.innerHTML = `<span class="icon">${p.icon}</span>${p.text}`;
        panelPills.appendChild(pill);
    });

    if (loc.image) {
        panelImg.src = loc.image;
        panelImg.style.display = 'block';
        panelPlaceholder.style.display = 'none';
    } else {
        panelImg.style.display = 'none';
        panelPlaceholder.style.display = 'flex';
        panelPlaceholder.textContent = loc.emoji || '📍';
    }

    panel.classList.add('open');
    hint.classList.add('hidden');
}

function closePanel() {
    if (activeMarker && activeLocIdx !== null) {
        activeMarker.setIcon(makeIcon(LOCATIONS[activeLocIdx].color, false));
    }
    activeMarker = null;
    activeLocIdx = null;
    panel.classList.remove('open');
    hint.classList.remove('hidden');
}

closeBtn.addEventListener('click', closePanel);

// ── ADD MARKERS ────────────────────────────────────────────────────────
LOCATIONS.forEach(loc => {
    const marker = L.marker([loc.lat, loc.lng], { icon: makeIcon(loc.color, false) }).addTo(map);
    marker.on('click', () => {
        openPanel(loc, marker);
        map.panTo([loc.lat, loc.lng], { animate: true, duration: 0.5 });
    });
});
